import os, base64
from fastapi import FastAPI, Response, Header, HTTPException
from pydantic import BaseModel
from weasyprint import HTML

app = FastAPI(title="Sales Consulting - Motore Fatture")
API_KEY = os.environ.get("API_KEY", "")   # imposta una chiave segreta su Render

LOGO = "data:image/png;base64,"
EMIT = dict(nome="Sales Consulting Int. SL", dni="B72828155",
            ind="Calle Las Dalias 12, Centro Comercial San Agustín planta 5, FINCA 340-342",
            cap="San Agustín, 35100", prov="Las Palmas de Gran Canaria",
            email="salesconsultingint@gmail.com")
WORD_NS = "Operación no sujeta al IGIC conforme a la Ley de localización, Artículo 17 de la Ley 20/1991."
WORD_IVA = "A efectos de IVA, Inversión de Sujeto Pasivo."

def eur(n):
    s = f"{float(n):,.2f}"
    return s.replace(",", "§").replace(".", ",").replace("§", ".") + " €"

class Cliente(BaseModel):
    nome: str; cif: str = ""; ind: str = ""; cap: str = ""; email: str = ""; tel: str = ""

class FatturaIn(BaseModel):
    tipo: str            # 'privato' | 'azienda' | 'canarie' | 'abono'
    numero: str
    data: str            # gg/mm/aaaa
    concetto: str
    importo: float       # totale (lordo). Per canarie è il totale, IGIC scorporato.
    pagamento: str = ""
    cliente: Cliente

def build_html(d: FatturaIn):
    abono = d.tipo == "abono"; canarie = d.tipo == "canarie"
    title = "ABONO" if abono else "FACTURA"; tot = d.importo
    if canarie:
        net = round(tot/1.07, 2); igic = round(tot-net, 2)
        rows = f'<tr><td>{d.concetto}</td><td class="r">{eur(net)}</td></tr><tr><td>IGIC (+7%)</td><td class="r">{eur(igic)}</td></tr>'
        note = ""
    else:
        rows = f'<tr><td>{d.concetto}</td><td class="r">{eur(tot)}</td></tr>'
        note = WORD_NS + (("<br>" + WORD_IVA) if d.tipo == "azienda" else "")
    pago = "" if abono else f'<div><span>Pagamento</span><b>{d.pagamento}</b></div>'
    c = d.cliente
    return f"""<html><head><meta charset="utf-8"><style>
    @page{{size:A4;margin:0}} *{{box-sizing:border-box;font-family:'Helvetica Neue',Arial,sans-serif;color:#1f2733}} body{{margin:0}}
    .wrap{{padding:42px 46px}}
    .top{{display:flex;justify-content:space-between;align-items:flex-start;border-bottom:3px solid #16365c;padding-bottom:18px}}
    .brand img{{height:60px}} .doc{{text-align:right}} .doc .t{{font-size:30px;font-weight:800;color:#16365c;letter-spacing:3px}} .doc .m{{font-size:12px;color:#55607a;margin-top:6px}} .doc .m b{{color:#1f2733}}
    .parties{{display:flex;gap:26px;margin-top:26px}} .card{{flex:1;background:#f6f8fb;border:1px solid #e6ebf2;border-radius:10px;padding:16px 18px}} .card h4{{margin:0 0 10px;font-size:10px;letter-spacing:2px;color:#16365c;text-transform:uppercase}} .card .l{{font-size:11px;color:#8a93a3;margin-top:7px}} .card .v{{font-size:12.5px;font-weight:600}}
    table{{width:100%;border-collapse:collapse;margin-top:28px}} thead th{{background:#16365c;color:#fff;font-size:11px;letter-spacing:1px;text-align:left;padding:11px 14px}} thead th.r,td.r{{text-align:right}} tbody td{{padding:13px 14px;border-bottom:1px solid #e6ebf2;font-size:12.5px}}
    .tot{{display:flex;justify-content:flex-end;margin-top:16px}} .totbox{{min-width:240px}} .totbox .grand{{background:#fff;color:#111;border:2px solid #111;border-radius:8px;font-size:15px;font-weight:800;padding:11px 14px;display:flex;justify-content:space-between}}
    .note{{margin-top:30px;padding:14px 16px;background:#fff8ec;border:1px solid #f0e0c0;border-radius:8px;font-size:11px;color:#6b5a36;line-height:1.5}}
    .pay{{margin-top:18px;font-size:12px}} .pay div{{display:flex;gap:10px}} .pay span{{color:#8a93a3}}
    .foot{{position:fixed;bottom:24px;left:46px;right:46px;border-top:1px solid #e6ebf2;padding-top:10px;font-size:9.5px;color:#a0a8b6;text-align:center}}
    </style></head><body><div class="wrap">
      <div class="top"><div class="brand"><img src="{LOGO}"></div>
        <div class="doc"><div class="t">{title}</div><div class="m">Nº {d.numero}<br>Fecha <b>{d.data}</b></div></div></div>
      <div class="parties">
        <div class="card"><h4>Emittente</h4><div class="v">{EMIT['nome']}</div><div class="l">CIF / DNI</div><div class="v">{EMIT['dni']}</div><div class="l">Indirizzo fiscale</div><div class="v">{EMIT['ind']}</div><div class="v">{EMIT['cap']} · {EMIT['prov']}</div><div class="l">Email</div><div class="v">{EMIT['email']}</div></div>
        <div class="card"><h4>Cliente</h4><div class="v">{c.nome}</div><div class="l">CIF / Codice Fiscale</div><div class="v">{c.cif}</div><div class="l">Indirizzo</div><div class="v">{c.ind}</div><div class="v">{c.cap}</div><div class="l">Email · Tel</div><div class="v">{c.email or '/'} · {c.tel or '/'}</div></div>
      </div>
      <table><thead><tr><th>Concepto</th><th class="r">Importe</th></tr></thead><tbody>{rows}</tbody></table>
      <div class="tot"><div class="totbox"><div class="grand"><span>TOTALE</span><span>{eur(tot)}</span></div></div></div>
      {('<div class="pay">'+pago+'</div>') if pago else ''}
      {('<div class="note">'+note+'</div>') if note else ''}
      <div class="foot">{EMIT['nome']} · CIF {EMIT['dni']} · {EMIT['ind']} · {EMIT['email']}</div>
    </div></body></html>"""

@app.get("/")
def health(): return {"ok": True, "service": "fatture Sales Consulting"}

@app.post("/fattura")
def fattura(d: FatturaIn, x_api_key: str = Header(default="")):
    if API_KEY and x_api_key != API_KEY:
        raise HTTPException(status_code=401, detail="API key non valida")
    pdf = HTML(string=build_html(d)).write_pdf()
    return Response(content=pdf, media_type="application/pdf")
